import Foundation

/// Build-time provenance for this vendored MarmotKit bundle.
///
/// Regenerated by `darkmatter-ios/scripts/sync-bindings.sh` on every rebuild,
/// so the app can show which darkmatter commit it's running against without a
/// runtime file lookup (the MARMOT_VERSION text file isn't bundled into the
/// app target).
public enum MarmotKitVersion {
    public static let darkmatterSHA = "5617f8b"
    public static let builtAt = "2026-05-21T07:12:00Z"
    public static let uniffiVersion = "0.28.3"
}
